#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;

my $log_dir = "/path/to/log/files";
my $filename = $cgi->param('logfile');

if ($filename =~ /^([-\@\w.]+)$/) {
    $filename = $1;
} else {
    die "Bad file name!";
}

open(FH, "<", "$log_dir/$filename") or die "Cannot open file: $!";

print $cgi->header('text/plain');

while (<FH>) {
    print $_;
}

close(FH);